def get_help_record(self, ctx: Context) -> tuple[str, str] | None:
    if self.hidden:
        return None

    any_prefix_is_slash = False

    def _write_opts(opts: cabc.Sequence[str]) -> str:
        nonlocal any_prefix_is_slash

        rv, any_slashes = join_options(opts)

        if any_slashes:
            any_prefix_is_slash = True

        if not self.is_flag and not self.count:
            rv += f" {self.make_metavar(ctx=ctx)}"

        return rv

    rv = [_write_opts(self.opts)]

    if self.secondary_opts:
        rv.append(_write_opts(self.secondary_opts))

    help = self.help or ""

    extra = self.get_help_extra(ctx)
    extra_items = []
    if "envvars" in extra:
        extra_items.append(
            _("env var: {var}").format(var=", ".join(extra["envvars"]))
        )
    if "default" in extra:
        extra_items.append(_("default: {default}").format(default=extra["default"]))
    if "range" in extra:
        extra_items.append(extra["range"])
    if "required" in extra:
        extra_items.append(_(extra["required"]))

    if extra_items:
        extra_str = "; ".join(extra_items)
        help = f"{help}  [{extra_str}]" if help else f"[{extra_str}]"

    return ("; " if any_prefix_is_slash else " / ").join(rv), help

def get_help_extra(self, ctx: Context) -> types.OptionHelpExtra:
    extra: types.OptionHelpExtra = {}

    if self.show_envvar:
        envvar = self.envvar

        if envvar is None:
            if (
                self.allow_from_autoenv
                and ctx.auto_envvar_prefix is not None
                and self.name is not None
            ):
                envvar = f"{ctx.auto_envvar_prefix}_{self.name.upper()}"

        if envvar is not None:
            if isinstance(envvar, str):
                extra["envvars"] = (envvar,)
            else:
                extra["envvars"] = tuple(str(d) for d in envvar)

    # Temporarily enable resilient parsing to avoid type casting
    # failing for the default. Might be possible to extend this to
    # help formatting in general.
    resilient = ctx.resilient_parsing
    ctx.resilient_parsing = True

    try:
        default_value = self.get_default(ctx, call=False)
    finally:
        ctx.resilient_parsing = resilient

    show_default = False
    show_default_is_str = False

    if self.show_default is not None:
        if isinstance(self.show_default, str):
            show_default_is_str = show_default = True
        else:
            show_default = self.show_default
    elif ctx.show_default is not None:
        show_default = ctx.show_default

    if show_default_is_str or (show_default and (default_value is not None)):
        if show_default_is_str:
            default_string = f"({self.show_default})"
        elif isinstance(default_value, (list, tuple)):
            default_string = ", ".join(str(d) for d in default_value)
        elif inspect.isfunction(default_value):
            default_string = _("(dynamic)")
        elif self.is_bool_flag and self.secondary_opts:
            # For boolean flags that have distinct True/False opts,
            # use the opt without prefix instead of the value.
            default_string = _split_opt(
                (self.opts if default_value else self.secondary_opts)[0]
            )[1]
        elif self.is_bool_flag and not self.secondary_opts and not default_value:
            default_string = ""
        elif default_value == "":
            default_string = '""'
        else:
            default_string = str(default_value)

        if default_string:
            extra["default"] = default_string

    if (
        isinstance(self.type, types._NumberRangeBase)
        # skip count with default range type
        and not (self.count and self.type.min == 0 and self.type.max is None)
    ):
        range_str = self.type._describe_range()

        if range_str:
            extra["range"] = range_str

    if self.required:
        extra["required"] = "required"

    return extra

@t.overload
def get_default(
    self, ctx: Context, call: t.Literal[True] = True
) -> t.Any | None: ...

@t.overload
def get_default(
    self, ctx: Context, call: bool = ...
) -> t.Any | t.Callable[[], t.Any] | None: ...

def get_default(
    self, ctx: Context, call: bool = True
) -> t.Any | t.Callable[[], t.Any] | None:
    # If we're a non boolean flag our default is more complex because
    # we need to look at all flags in the same group to figure out
    # if we're the default one in which case we return the flag
    # value as default.
    if self.is_flag and not self.is_bool_flag:
        for param in ctx.command.params:
            if param.name == self.name and param.default:
                return t.cast(Option, param).flag_value

        return None

    return super().get_default(ctx, call=call)

def prompt_for_value(self, ctx: Context) -> t.Any:
    """This is an alternative flow that can be activated in the full
    value processing if a value does not exist.  It will prompt the
    user until a valid value exists and then returns the processed
    value as result.
    """
    assert self.prompt is not None

    # Calculate the default before prompting anything to be stable.
    default = self.get_default(ctx)

    # If this is a prompt for a flag we need to handle this
    # differently.
    if self.is_bool_flag:
        return confirm(self.prompt, default)

    # If show_default is set to True/False, provide this to `prompt` as well. For
    # non-bool values of `show_default`, we use `prompt`'s default behavior
    prompt_kwargs: t.Any = {}
    if isinstance(self.show_default, bool):
        prompt_kwargs["show_default"] = self.show_default

    return prompt(
        self.prompt,
        default=default,
        type=self.type,
        hide_input=self.hide_input,
        show_choices=self.show_choices,
        confirmation_prompt=self.confirmation_prompt,

def get_default(
    self, ctx: Context, call: t.Literal[True] = True
) -> t.Any | None: ...

@t.overload
def get_default(
    self, ctx: Context, call: bool = ...
) -> t.Any | t.Callable[[], t.Any] | None: ...

def get_default(
    self, ctx: Context, call: bool = True
) -> t.Any | t.Callable[[], t.Any] | None:
    """Get the default for the parameter. Tries
    :meth:`Context.lookup_default` first, then the local default.

    :param ctx: Current context.
    :param call: If the default is a callable, call it. Disable to
        return the callable instead.

    .. versionchanged:: 8.0.2
        Type casting is no longer performed when getting a default.

    .. versionchanged:: 8.0.1
        Type casting can fail in resilient parsing mode. Invalid
        defaults will not prevent showing help text.

    .. versionchanged:: 8.0
        Looks at ``ctx.default_map`` first.

    .. versionchanged:: 8.0
        Added the ``call`` parameter.
    """
    value = ctx.lookup_default(self.name, call=False)  # type: ignore

    if value is None:
        value = self.default

    if call and callable(value):
        value = value()

    return value

def add_to_parser(self, parser: _OptionParser, ctx: Context) -> None:
    raise NotImplementedError()

def consume_value(
    self, ctx: Context, opts: cabc.Mapping[str, t.Any]
) -> tuple[t.Any, ParameterSource]:
    value = opts.get(self.name)  # type: ignore
    source = ParameterSource.COMMANDLINE

    if value is None:
        value = self.value_from_envvar(ctx)
        source = ParameterSource.ENVIRONMENT

    if value is None:
        value = ctx.lookup_default(self.name)  # type: ignore
        source = ParameterSource.DEFAULT_MAP

    if value is None:
        value = self.get_default(ctx)
        source = ParameterSource.DEFAULT

    return value, source

def type_cast_value(self, ctx: Context, value: t.Any) -> t.Any:
    """Convert and validate a value against the option's
    :attr:`type`, :attr:`multiple`, and :attr:`nargs`.
    """
    if value is None:
        return () if self.multiple or self.nargs == -1 else None

    def check_iter(value: t.Any) -> cabc.Iterator[t.Any]:
        try:
            return _check_iter(value)
        except TypeError:
            # This should only happen when passing in args manually,
            # the parser should construct an iterable when parsing
            # the command line.
            raise BadParameter(
                _("Value must be an iterable."), ctx=ctx, param=self
            ) from None

    if self.nargs == 1 or self.type.is_composite:

        def convert(value: t.Any) -> t.Any:
            return self.type(value, param=self, ctx=ctx)

    elif self.nargs == -1:

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            return tuple(self.type(x, self, ctx) for x in check_iter(value))

    else:  # nargs > 1

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            value = tuple(check_iter(value))

            if len(value) != self.nargs:
                raise BadParameter(
                    ngettext(
                        "Takes {nargs} values but 1 was given.",
                        "Takes {nargs} values but {len} were given.",
                        len(value),
                    ).format(nargs=self.nargs, len=len(value)),
                    ctx=ctx,
                    param=self,
                )

            return tuple(self.type(x, self, ctx) for x in value)

    if self.multiple:
        return tuple(convert(x) for x in check_iter(value))

    return convert(value)

def value_is_missing(self, value: t.Any) -> bool:
    if value is None:
        return True

    if (self.nargs != 1 or self.multiple) and value == ():
        return True

    return False

def process_value(self, ctx: Context, value: t.Any) -> t.Any:
    value = self.type_cast_value(ctx, value)

    if self.required and self.value_is_missing(value):
        raise MissingParameter(ctx=ctx, param=self)

    if self.callback is not None:
        value = self.callback(ctx, self, value)

    return value

def resolve_envvar_value(self, ctx: Context) -> str | None:
    if self.envvar is None:
        return None

    if isinstance(self.envvar, str):
        rv = os.environ.get(self.envvar)

        if rv:
            return rv

def handle_parse_result(
    self, ctx: Context, opts: cabc.Mapping[str, t.Any], args: list[str]
) -> tuple[t.Any, list[str]]:
    with augment_usage_errors(ctx, param=self):
        value, source = self.consume_value(ctx, opts)

        if (
            self.deprecated
            and value is not None
            and source
            not in (
                ParameterSource.DEFAULT,
                ParameterSource.DEFAULT_MAP,
            )
        ):
            extra_message = (
                f" {self.deprecated}" if isinstance(self.deprecated, str) else ""
            )
            message = _(
                "DeprecationWarning: The {param_type} {name!r} is deprecated."
                "{extra_message}"
            ).format(
                param_type=self.param_type_name,
                name=self.human_readable_name,
                extra_message=extra_message,
            )
            echo(style(message, fg="red"), err=True)

        ctx.set_parameter_source(self.name, source)  # type: ignore

        try:
            value = self.process_value(ctx, value)
        except Exception:
            if not ctx.resilient_parsing:
                raise

            value = None

    if self.expose_value:
        ctx.params[self.name] = value  # type: ignore

    return value, args

def get_help_record(self, ctx: Context) -> tuple[str, str] | None:
    pass

